const items = $input.all();
const outputs = [];

for (let i = 0; i < items.length; i++) {
  const bin = items[i].binary || {};
  const keys = Object.keys(bin);

  if (!keys.length) {
    outputs.push({ json: { key: '', fileName: '', mimeType: '', url: '' } });
    continue;
  }

  for (const key of keys) {
    const meta = bin[key] || {};
    let url = '';
    try {
      const buf = await this.helpers.getBinaryDataBuffer(i, key);
      const mime = meta.mimeType || meta.mimetype || 'application/octet-stream';
      const base64 = Buffer.isBuffer(buf) ? buf.toString('base64') : Buffer.from(buf).toString('base64');
      url = base64 ? `data:${mime};base64,${base64}` : '';
    } catch (_) {
      const mime = meta.mimeType || meta.mimetype || 'application/octet-stream';
      const data = meta.data;
      if (typeof data === 'string' && data.length) url = `data:${mime};base64,${data}`;
    }

    outputs.push({
      json: {
        key,
        fileName: meta.fileName || meta.filename || key,
        mimeType: meta.mimeType || meta.mimetype || '',
        url
      }
    });
  }
}

return outputs.length ? outputs : [{ json: { key: '', fileName: '', mimeType: '', url: '' } }];

// ================================================
// n8n Code 节点专用代码（JavaScript）
// 功能：
// 1) 获取当前节点输入数据
// 2) 提取当前输入 binary 中所有图片
// 3) 获取 Edit Fields 节点 cpimage* 图片
// 4) 生成 cleanJsonString
// 5) 从上游文字中提取“第二部分：AI生成提示词”
// 6) 将输出图片键名重命名为：1图、2图、3图...
// ================================================

const processInputAndImages = () => {
  try {
    // 1. 获取当前节点输入
    const inputItems = $input.all();
    const firstInput = inputItems && inputItems.length > 0 ? inputItems[0] : {};
    const inputJson = firstInput.json || {};
    const inputBinary = firstInput.binary || {};

    // 2. 提取当前输入中的所有 binary
    const allImages = {};
    let totalImageCount = 0;

    Object.keys(inputBinary).forEach((key) => {
      if (inputBinary[key]) {
        allImages[key] = { ...inputBinary[key] };
        totalImageCount++;
      }
    });

    console.log("当前输入 binary 总键数:", Object.keys(inputBinary).length);
    console.log("提取到的图片数:", totalImageCount);
    console.log("图片键名列表:", Object.keys(allImages));

    // 3. 获取 Edit Fields 节点的 cpimage*
    let editFieldsImages = [];
    let editFieldsBinary = {};
    let editFieldsImageCount = 0;
    let editFieldsConnected = false;

    try {
      const editFieldsItems = $("Edit Fields").all();

      if (editFieldsItems && editFieldsItems.length > 0) {
        editFieldsItems.forEach((item, idx) => {
          const itemBinary = item.binary || {};

          Object.keys(itemBinary).forEach((key) => {
            if (key.startsWith("cpimage") && itemBinary[key]) {
              const img = itemBinary[key];
              editFieldsImages.push({
                fieldName: key,
                fileName: img.fileName || "",
                mimeType: img.mimeType || "",
                fileExtension: img.fileExtension || "",
                fileSize: img.fileSize || "",
                sourceItemIndex: idx,
              });

              editFieldsBinary[`editFields_${key}_${idx}`] = { ...itemBinary[key] };
              editFieldsImageCount++;
            }
          });
        });

        if (editFieldsImageCount > 0) {
          editFieldsConnected = true;
          console.log(`成功从 Edit Fields 节点提取 ${editFieldsImageCount} 张图片`);
        }
      }
    } catch (editFieldsErr) {
      console.log("获取 Edit Fields 失败:", editFieldsErr.message);
    }

    // 4. 生成 cleanJsonString
    let cleanJsonString = "";
    try {
      cleanJsonString = JSON.stringify(inputJson);
    } catch (jsonErr) {
      console.log("生成干净字符串失败:", jsonErr.message);
      cleanJsonString = JSON.stringify(inputJson);
    }

    // 提取“第二部分：AI生成提示词”
    const extractSecondPart = (text) => {
      if (typeof text !== "string" || !text.trim()) return "";

      const normalized = text.replace(/\r\n/g, "\n");
      const match = normalized.match(
        /###\s*第二部分[^\n]*\n+([\s\S]*?)(?:\n###\s*第三部分[^\n]*|$)/i
      );

      if (!match || !match[1]) return "";
      return match[1].trim();
    };

    // 兼容不同输入结构，尽量找到上游 output 文本
    let upstreamOutputText = "";
    if (typeof inputJson.output === "string") {
      upstreamOutputText = inputJson.output;
    } else if (Array.isArray(inputJson) && inputJson[0] && typeof inputJson[0].output === "string") {
      upstreamOutputText = inputJson[0].output;
    } else if (Array.isArray(inputItems) && inputItems[0]?.json?.output) {
      upstreamOutputText = String(inputItems[0].json.output);
    }

    const secondPartRaw = extractSecondPart(upstreamOutputText);

    // 去掉首尾括号/引号
    let secondPartPrompt = secondPartRaw;
    if (secondPartPrompt.startsWith('"') && secondPartPrompt.endsWith('"')) {
      secondPartPrompt = secondPartPrompt.slice(1, -1).trim();
    }
    if (secondPartPrompt.startsWith("(") && secondPartPrompt.endsWith(")")) {
      secondPartPrompt = secondPartPrompt.slice(1, -1).trim();
    }

    // 5. 合并 binary
    const mergedBinaryRaw = {
      ...allImages,
      ...editFieldsBinary,
    };

    // 6. 统一重命名 binary 键名为：1图、2图、3图...
    const renamedBinary = {};
    const imageKeyMap = []; // oldKey -> newKey 方便排查

    Object.keys(mergedBinaryRaw).forEach((oldKey, index) => {
      const newKey = `${index + 1}图`;
      const img = { ...mergedBinaryRaw[oldKey] };

      // 同步改 fileName（保留原扩展名）
      const ext =
        img.fileExtension ||
        (img.fileName && img.fileName.includes(".")
          ? img.fileName.split(".").pop()
          : "");
      img.fileName = ext ? `${newKey}.${ext}` : newKey;

      renamedBinary[newKey] = img;
      imageKeyMap.push({ oldKey, newKey });
    });

    // 7. 返回
    return [
      {
        json: {
          inputData: inputJson,

          allImages: allImages,
          totalImageCount: totalImageCount,
          imageKeys: Object.keys(allImages),

          editFieldsImages: editFieldsImages,
          editFieldsImageCount: editFieldsImageCount,
          editFieldsConnected: editFieldsConnected,

          finalTotalImageCount: Object.keys(renamedBinary).length,
          source: "merged_all_images_and_editFields",

          cleanJsonString: cleanJsonString,

          upstreamOutputText: upstreamOutputText,
          secondPartRaw: secondPartRaw,
          secondPartPrompt: secondPartPrompt,

          // 新增：重命名后的键名与映射
          renamedImageKeys: Object.keys(renamedBinary), // ["1图","2图"...]
          imageKeyMap: imageKeyMap
        },
        binary: renamedBinary,
      },
    ];
  } catch (err) {
    console.log("执行失败:", err.message);
    return [
      {
        json: {
          error: "执行失败",
          errorDetail: err.message,
        },
      },
    ];
  }
};

// 执行
return processInputAndImages();

