  { label: "4:5", value: 4 / 5 },
  { label: "5:4", value: 5 / 4 },
  { label: "9:16", value: 9 / 16 },
];

function getClosestRatio(width, height) {
  if (!width || !height) return null;
  const actual = width / height;

  let best = TARGET_RATIOS[0];
  let minDiff = Math.abs(actual - best.value);

  for (let i = 1; i < TARGET_RATIOS.length; i++) {
    const diff = Math.abs(actual - TARGET_RATIOS[i].value);
    if (diff < minDiff) {
      minDiff = diff;
      best = TARGET_RATIOS[i];
    }
  }

  return {
    closestRatio: best.label,
    actualRatio: Number(actual.toFixed(6)),
    ratioDiff: Number(minDiff.toFixed(6)),
  };
}

function parsePng(buf) {
  if (buf.length < 24) return null;
  const sig = [0x89, 0x50, 0x4e, 0x47, 0x0d, 0x0a, 0x1a, 0x0a];
  for (let i = 0; i < sig.length; i++) {
    if (buf[i] !== sig[i]) return null;
  }
  return { width: buf.readUInt32BE(16), height: buf.readUInt32BE(20), format: "png" };
}

function parseGif(buf) {
  if (buf.length < 10) return null;
  const header = buf.toString("ascii", 0, 6);
  if (header !== "GIF87a" && header !== "GIF89a") return null;
  return { width: buf.readUInt16LE(6), height: buf.readUInt16LE(8), format: "gif" };
}

function parseJpeg(buf) {
  if (buf.length < 4 || buf[0] !== 0xff || buf[1] !== 0xd8) return null;

  let offset = 2;
  while (offset + 9 < buf.length) {
    if (buf[offset] !== 0xff) {
      offset++;
      continue;
    }

    const marker = buf[offset + 1];
    offset += 2;

    if (marker === 0xd8 || marker === 0xd9) continue;
    if (offset + 1 >= buf.length) break;

    const segmentLength = buf.readUInt16BE(offset);
    if (segmentLength < 2 || offset + segmentLength > buf.length) break;

    const isSOF =
      (marker >= 0xc0 && marker <= 0xc3) ||
      (marker >= 0xc5 && marker <= 0xc7) ||
      (marker >= 0xc9 && marker <= 0xcb) ||
      (marker >= 0xcd && marker <= 0xcf);

    if (isSOF) {
      const height = buf.readUInt16BE(offset + 3);
      const width = buf.readUInt16BE(offset + 5);
      return { width, height, format: "jpeg" };
    }

    offset += segmentLength;
  }

  return null;
}

function parseWebp(buf) {
  if (buf.length < 30) return null;
  if (buf.toString("ascii", 0, 4) !== "RIFF") return null;
  if (buf.toString("ascii", 8, 12) !== "WEBP") return null;

  const chunk = buf.toString("ascii", 12, 16);

  // VP8X
  if (chunk === "VP8X") {
    const widthMinus1 = buf[24] | (buf[25] << 8) | (buf[26] << 16);
    const heightMinus1 = buf[27] | (buf[28] << 8) | (buf[29] << 16);
    return { width: widthMinus1 + 1, height: heightMinus1 + 1, format: "webp" };
  }

  // VP8L
  if (chunk === "VP8L" && buf[20] === 0x2f) {
    const b0 = buf[21];
    const b1 = buf[22];
    const b2 = buf[23];
    const b3 = buf[24];

    const width = 1 + (((b1 & 0x3f) << 8) | b0);
    const height = 1 + (((b3 & 0x0f) << 10) | (b2 << 2) | ((b1 & 0xc0) >> 6));
    return { width, height, format: "webp" };
  }

  return null;
}

function parseByHeader(buf) {
  return parsePng(buf) || parseJpeg(buf) || parseGif(buf) || parseWebp(buf);
}

