    return {
      width: Number(metaWidth),
      height: Number(metaHeight),
      detectedFormat: (imgObj.mimeType || "").split("/")[1] || null,
      dimensionSource: "metadata",
    };
  }

  // 2) 尝试 data(base64)
  if (imgObj.data) {
    try {
      const buf = Buffer.from(imgObj.data, "base64");
      const parsed = parseByHeader(buf);
      if (parsed) {
        return {
          width: parsed.width,
          height: parsed.height,
          detectedFormat: parsed.format,
          dimensionSource: "data_base64",
        };
      }
    } catch (_) {}
  }

  // 3) 用 n8n helper 拿真实二进制 buffer（关键）
  try {
    const buf = await this.helpers.getBinaryDataBuffer(itemIndex, key);
    const parsed = parseByHeader(buf);
    if (parsed) {
      return {
        width: parsed.width,
        height: parsed.height,
        detectedFormat: parsed.format,
        dimensionSource: "binary_buffer",
      };
    }
  } catch (e) {
    console.log(`读取二进制失败: item=${itemIndex}, key=${key}, err=${e.message}`);
  }

  return null;
}

async function run() {
  const itemIndex = 0; // 当前按单 item 处理
  const binary = $input.item?.binary || {};
  const keys = Object.keys(binary);

  const hasCkimage = keys.some((k) => k.startsWith("ckimage"));
  const hasCpimage = keys.some((k) => k.startsWith("cpimage"));

  // 两个前缀必须同时存在
  if (!hasCkimage || !hasCpimage) {
    console.log("缺少 ckimage 或 cpimage 前缀的图片，不进行提取");
    return [
      {
        json: {
          message: "缺少 ckimage 或 cpimage 前缀的图片，不提取 binary",
          hasCkimage,
          hasCpimage,
          extracted: false,
        },
        binary: {},
      },
    ];
  }

  // 先 ckimage，再 cpimage
  const orderedKeys = [
    ...keys.filter((k) => k.startsWith("ckimage")),
    ...keys.filter((k) => k.startsWith("cpimage")),
  ];

  const extractedBinary = {};
  const imageInfos = [];

  for (let i = 0; i < orderedKeys.length; i++) {
    const oldKey = orderedKeys[i];
    const outputKey = oldKey; // 保持原键名，不改成 1图/2图
    const imgObj = { ...binary[oldKey] };

    extractedBinary[outputKey] = imgObj;

    const dims = await getDimsFromBinary.call(this, itemIndex, oldKey, imgObj);
    const ratio = dims ? getClosestRatio(dims.width, dims.height) : null;

    imageInfos.push({
      outputKey: outputKey,
      originalKey: oldKey,
      fileName: imgObj.fileName || "",
      mimeType: imgObj.mimeType || "",
      width: dims ? dims.width : null,
      height: dims ? dims.height : null,
      pixelText: dims ? `${dims.width}x${dims.height}` : null,
      detectedFormat: dims ? dims.detectedFormat : null,
      dimensionSource: dims ? dims.dimensionSource : null,
      closestRatio: ratio ? ratio.closestRatio : null,
      actualRatio: ratio ? ratio.actualRatio : null,
      ratioDiff: ratio ? ratio.ratioDiff : null,
    });
  }

  console.log(`成功提取 ckimage 和 cpimage 图片，共 ${orderedKeys.length} 张`);

  return [
    {
      json: {
        message: "成功提取 ckimage 和 cpimage 的图片，并完成像素与比例识别",
        ckimageCount: keys.filter((k) => k.startsWith("ckimage")).length,
        cpimageCount: keys.filter((k) => k.startsWith("cpimage")).length,
        extractedCount: orderedKeys.length,
        extracted: true,
        imageInfos,
      },
      binary: extractedBinary, // 这里仍是原始 ckimage/cpimage 键名
    },
  ];
}

return await run();
